import React from 'react';
import { Row, Col } from 'react-bootstrap';
import Product from './Product'; 
import Paginate from './Paginate'; 
// Importamos los estilos del módulo (ya definidos en tu Canvas)
import styles from './ProductList.module.css';

const ProductList = ({ products, loading, error, pages, page, setPage }) => {
    return (
        <>
            {/* Si no hay productos, mostramos el estado vacío estilizado */}
            {(!products || products.length === 0) ? (
                <div className={styles.emptyContainer}>
                    <i className={`fas fa-box-open ${styles.emptyIcon}`}></i>
                    <h4 className={styles.emptyTitle}>¡Lo sentimos! No hay productos en esta sección.</h4>
                </div>
            ) : (
                <>
                    {/* Renderizado de la cuadrícula de productos */}
                    <Row>
                        {products.map((product) => (
                            <Col 
                                key={product._id} 
                                // Layout Responsivo: 1 en móvil, 2 en tablet, 3 en desktop, 4 en pantallas muy anchas
                                xs={12} sm={6} md={4} lg={3} 
                                // Usamos la clase del módulo para alinear alturas
                                className={styles.gridCol}
                            >
                                <Product product={product} />
                            </Col>
                        ))}
                    </Row>
                    
                    {/* Paginación */}
                    {(pages > 1) && (
                        <div className="d-flex justify-content-center mt-5">
                            <Paginate pages={pages} page={page} setPage={setPage} />
                        </div>
                    )}
                </>
            )}
        </>
    );
};

export default ProductList;
